import React from "react";

function SchemeMastersForm({ module }) {

   const handleSubmit = (e) => {
      e.preventDefault();
      alert(`${module.title} saved successfully.`);
   };

   const handleCancel = () => {
      console.log("Cancelled");
   };

   const renderField = (field, index) => {
      const fieldId = `field-${index}`;

      if (field.type === "textarea") {
         return (
            <textarea
               id={fieldId}
               className="form-control form-control-sm"
               placeholder={field.placeholder}
            />
         );
      }

      if (field.type === "select") {
         return (
            <select
               id={fieldId}
               className="form-select form-select-sm"
            >
               <option value="">Select</option>
               {field.options?.map((option, i) => (
                  <option key={i} value={option}>
                     {option}
                  </option>
               ))}
            </select>
         );
      }

      return (
         <input
            type={field.type || "text"}
            id={fieldId}
            className="form-control form-control-sm"
            placeholder={field.placeholder}
         />
      );
   };

   return (
      <div className="card border-0 shadow-sm">
         <div
            className="card-header border-0"
            style={{
               background: module.bg,
               borderLeft: `5px solid ${module.color}`
            }}
         >
            <div className="d-flex align-items-center">
               <div>
                  <h5
                     className="card-title m-0 fw-bold"
                     style={{ color: module.color }}
                  >
                     {module.formTitle}
                  </h5>

                  <small>
                     Fill in the details below and save.
                  </small>
               </div>
            </div>
         </div>

         <div className="card-body" style={{ minHeight: "600px" }}>
            <form onSubmit={handleSubmit}>
               <div className="row">
                  {module.fields.map((field, index) => (
                     <div className="col-md-6 mb-3" key={index}>
                        <label className="form-label form-label-sm">
                           {field.label}

                           {field.required && (
                              <span className="text-danger"> *</span>
                           )}
                        </label>

                        {renderField(field, index)}
                     </div>
                  ))}
               </div>

               <div className="text-end border-top pt-3">
                  <button
                     type="submit"
                     className="btn btn-primary btn-sm me-2"
                  >
                     <i className="fa fa-check"></i> Save
                  </button>

                  <button
                     type="button"
                     className="btn btn-danger btn-sm"
                     onClick={handleCancel}
                  >
                     <i className="fa fa-times"></i> Cancel
                  </button>
               </div>
            </form>
         </div>
      </div>
   );
}

export default SchemeMastersForm;
